// components/AdvancedSettings.tsx
import { useState, useEffect, useCallback } from "react";
import { TemperatureControl } from "./TemperatureControl";

const STORAGE_KEY = "chat:advanced-open";

interface Props {
  temperature: number;
  onTemperatureChange: (v: number) => void;
  maxTokens: number;
  onMaxTokensChange: (v: number) => void;
  systemPrompt: string;
  onSystemPromptChange: (v: string) => void;
}

export function AdvancedSettings(props: Props) {
  const [open, setOpen] = useState(() => {
    try {
      return localStorage.getItem(STORAGE_KEY) === "true";
    } catch {
      return false;
    }
  });

  const toggle = useCallback(() => {
    setOpen(prev => {
      const next = !prev;
      try { localStorage.setItem(STORAGE_KEY, String(next)); } catch {}
      return next;
    });
  }, []);

  return (
    <div className="advanced-settings">
      <button
        className="advanced-toggle"
        onClick={toggle}
        aria-expanded={open}
        aria-controls="advanced-panel"
      >
        <span>{open ? "▾" : "▸"} Advanced settings</span>
      </button>

      {open && (
        <div id="advanced-panel" className="advanced-panel">
          <fieldset>
            <legend>Model behaviour</legend>
            <TemperatureControl
              value={props.temperature}
              onChange={props.onTemperatureChange}
            />
            <label>
              Max tokens
              <input
                type="number"
                min={64}
                max={8096}
                step={64}
                value={props.maxTokens}
                onChange={e => props.onMaxTokensChange(parseInt(e.target.value, 10))}
              />
            </label>
          </fieldset>

          <fieldset>
            <legend>System prompt</legend>
            <textarea
              rows={4}
              value={props.systemPrompt}
              onChange={e => props.onSystemPromptChange(e.target.value)}
              placeholder="You are a helpful assistant...">
            </textarea>
          </fieldset>
        </div>
      )}
    </div>
  );
}

// hooks/useFeatureFlags.ts
import { useMemo } from "react";

interface User {
  roles: string[];
  featureFlags: Record<string, boolean>;
}

export function useFeatureFlags(user: User | null) {
  return useMemo(() => ({
    developerMode: user?.roles.includes("developer") ||
                   user?.featureFlags["developer_mode"] === true,
    exportApi:     user?.featureFlags["export_as_api"] === true,
    tokenCounter:  user?.featureFlags["show_token_count"] === true,
  }), [user]);
}

