// AdvancedSettings.test.tsx
import { render, screen, fireEvent } from "@testing-library/react";
import { AdvancedSettings } from "./AdvancedSettings";

const defaults = {
  temperature: 0.5,
  onTemperatureChange: jest.fn(),
  maxTokens: 2048,
  onMaxTokensChange: jest.fn(),
  systemPrompt: "",
  onSystemPromptChange: jest.fn(),
};

test("panel is collapsed by default", () => {
  render(<AdvancedSettings {...defaults} />);
  expect(screen.queryByRole("group", { name: "Model behaviour" })).toBeNull();
});

test("panel opens on click and aria-expanded updates", () => {
  render(<AdvancedSettings {...defaults} />);
  const btn = screen.getByRole("button", { name: /Advanced settings/ });
  expect(btn).toHaveAttribute("aria-expanded", "false");
  fireEvent.click(btn);
  expect(btn).toHaveAttribute("aria-expanded", "true");
  expect(screen.getByRole("group", { name: /Model behaviour/ })).toBeVisible();
});

test("persists open state to localStorage", () => {
  render(<AdvancedSettings {...defaults} />);
  fireEvent.click(screen.getByRole("button", { name: /Advanced settings/ }));
  expect(localStorage.getItem("chat:advanced-open")).toBe("true");
});

// DeveloperPanelVisibility.test.tsx
import { render, screen } from "@testing-library/react";
import { ChatLayout } from "./ChatLayout";

test("developer panel hidden for regular user", () => {
  render(<ChatLayout user={{ roles: [], featureFlags: {} }} />);
  expect(screen.queryByText(/Token count/i)).toBeNull();
});

test("developer panel visible for developer role", () => {
  render(<ChatLayout user={{ roles: ["developer"], featureFlags: {} }} />);
  expect(screen.getByText(/Token count/i)).toBeInTheDocument();
});
